import anthropic
import re
from collections import Counter
from concurrent.futures import ThreadPoolExecutor, as_completed

client = anthropic.Anthropic()


def extract_answer(text: str) -> str | None:
    """Extract final answer from a CoT response."""
    # Look for common answer patterns
    patterns = [
        r"(?:the answer is|answer:|=\s*)[\$]?([\d/\.]+)",
        r"(?:therefore|so|thus)[,.]?\s+(?:the answer is\s+)?([\d/\.]+)",
        r"([\d]+/[\d]+)\s*$",   # fraction at end of text
        r"(?:^|\n)([\d\.]+)\s*$",  # bare number at end
    ]
    for pat in patterns:
        m = re.search(pat, text, re.IGNORECASE | re.MULTILINE)
        if m:
            return m.group(1).strip()
    return None


def generate_one_sample(question: str, temperature: float) -> str | None:
    """Generate a single CoT sample and extract its answer."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        temperature=temperature,
        messages=[{
            "role": "user",
            "content": question + "\nLet's think step by step.",
        }],
    )
    return extract_answer(resp.content[0].text)


def self_consistency(
    question: str,
    n: int = 16,
    temperature: float = 0.7,
    early_stop_share: float = 0.80,
) -> dict:
    """
    Self-consistency with adaptive early stopping.
    Stops when the leading answer holds >= early_stop_share of votes so far.
    """
    answers: list[str] = []
    # Generate samples in parallel batches of 4
    batch_size = 4
    for batch_start in range(0, n, batch_size):
        with ThreadPoolExecutor(max_workers=batch_size) as pool:
            futures = [
                pool.submit(generate_one_sample, question, temperature)
                for _ in range(min(batch_size, n - batch_start))
            ]
            for fut in as_completed(futures):
                ans = fut.result()
                if ans:
                    answers.append(ans)

        # Early stop check after each batch
        if answers:
            top, top_n = Counter(answers).most_common(1)[0]
            if top_n / len(answers) >= early_stop_share:
                break

    counts = Counter(answers)
    winner, winner_votes = counts.most_common(1)[0] if counts else (None, 0)
    return {
        "answer": winner,
        "vote_share": winner_votes / len(answers) if answers else 0,
        "samples": len(answers),
        "distribution": dict(counts.most_common()),
    }


if __name__ == "__main__":
    q = (
        "A jar contains 4 red and 6 blue marbles. Two are drawn without "
        "replacement. What is the probability both are red?"
    )
    result = self_consistency(q, n=16, temperature=0.7)
    print(f"Answer: {result['answer']}")
    print(f"Confidence: {result['vote_share']:.1%} ({result['samples']} samples)")
    print(f"Distribution: {result['distribution']}")
